from pydantic import BaseModel, Field
from typing import Optional

class InvoiceSchema(BaseModel):
    invoice_number: str = Field(..., description="Unique invoice ID")
    date: str = Field(..., description="Invoice date YYYY-MM-DD")
    total_amount: float = Field(..., description="Total invoice amount")
    vendor_name: str = Field(..., description="Vendor/Supplier name")
    line_items: list[dict] = Field(default_factory=list)

    class Config:
        json_schema_extra = {"required": ["invoice_number", "date", "total_amount"]}

crew = Crew(
    agents=[extractor, validator],
    tasks=[extraction_task, validation_task],
    verbose=2
)

result = crew.kickoff(inputs={
    "document_text": "Invoice #INV-1234 dated 2024-01-15... Total: $1,250.00"
})
print(result)

