from crewai import Task

def vex_callback(task_output):
    result = vex.verify(
        data=task_output,
        spec=extraction_spec,
        context={"task": "invoice_extraction"}
    )
    if not result.valid:
        raise ValueError(f"Vex failed: {result.issues}")
    return task_output

extraction_task = Task(
    description="Extract invoice data...",
    agent=extractor,
    callback=vex_callback,  # Vex verification step
    output_pydantic=InvoiceSchema
)
